class Solution:
    def sumFourDivisors(self, nums):
        def divisor_sum(n):
            divs = []
            for d in range(1, n + 1):
                if n % d == 0:
                    divs.append(d)
                    if len(divs) > 4:
                        return 0
            return sum(divs) if len(divs) == 4 else 0
        return sum(divisor_sum(n) for n in nums)

