class Solution:
    def sumFourDivisors(self, nums):
        def four_div_sum(n):
            count = 0
            s = 0
            d = 1
            while d * d <= n:
                if n % d == 0:
                    count += 1
                    s += d
                    if d != n // d:
                        count += 1
                        s += n // d
                    if count > 4:
                        return 0
                d += 1
            return s if count == 4 else 0
        return sum(four_div_sum(n) for n in nums)

