var sumFourDivisors = function(nums) {
    function fourDivSum(n) {
        let count = 0, s = 0;
        for (let d = 1; d * d <= n; d++) {
            if (n % d === 0) {
                count++; s += d;
                if (d !== Math.floor(n / d)) { count++; s += Math.floor(n / d); }
                if (count > 4) return 0;
            }
        }
        return count === 4 ? s : 0;
    }
    let total = 0;
    for (const n of nums) total += fourDivSum(n);
    return total;
};
